import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { Menu, X, Instagram, Facebook } from "lucide-react";
import logo from "../assets/images/logo_final.png";

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);

  useEffect(() => {
    const onScroll = () => setIsScrolled(window.scrollY > 50);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  // lock background scroll
  useEffect(() => {
    document.body.style.overflow = isOpen ? "hidden" : "auto";
  }, [isOpen]);

  const menuItems = [
    { title: "Home", path: "/" },
    { title: "Academy", path: "/academy" },
    { title: "Pro Services", path: "/pro-services" },
    { title: "Gallery", path: "/gallery" },
    { title: "Our Story", path: "/story" },
    { title: "Connect", path: "/connect" },
  ];

  return (
    <>
      {/* ===== NAVBAR ===== */}
      <nav
        className={`fixed top-0 w-full z-50 transition-all duration-300 ${
          isScrolled
            ? "bg-charcoal/90 backdrop-blur-lg border-b border-gold/30"
            : "bg-charcoal/50 backdrop-blur-md"
        }`}
      >
        <div className="max-w-7xl mx-auto px-6 lg:px-12">
          <div className="flex h-20 items-center justify-between">
            <Link to="/">
              <img src={logo} alt="Logo" className="h-12" />
            </Link>

            {/* Desktop */}
            <div className="hidden md:flex gap-12">
              {menuItems.map((i) => (
                <Link
                  key={i.path}
                  to={i.path}
                  className="text-xs uppercase tracking-widest text-ivory/70 hover:text-gold"
                >
                  {i.title}
                </Link>
              ))}
            </div>

            {/* Mobile Toggle */}
            <button
              className="md:hidden text-gold"
              onClick={() => setIsOpen(true)}
            >
              <Menu size={28} />
            </button>
          </div>
        </div>
      </nav>

      {/* ===== MOBILE OVERLAY (OUTSIDE NAV) ===== */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            className="fixed inset-0 z-[100] bg-charcoal"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
          >
            {/* Close button */}
            <button
              className="absolute top-6 right-6 text-gold"
              onClick={() => setIsOpen(false)}
            >
              <X size={32} />
            </button>

            <div className="flex h-full flex-col items-center justify-center gap-10">
              {menuItems.map((item, i) => (
                <motion.div
                  key={item.path}
                  initial={{ y: 20, opacity: 0 }}
                  animate={{ y: 0, opacity: 1 }}
                  transition={{ delay: i * 0.06 }}
                >
                  <Link
                    to={item.path}
                    onClick={() => setIsOpen(false)}
                    className="text-2xl font-cinzel tracking-widest text-gold hover:text-ivory"
                  >
                    {item.title}
                  </Link>
                </motion.div>
              ))}

              <div className="flex gap-8 pt-12 border-t border-gold/40">
                <Instagram className="text-gold" size={26} />
                <Facebook className="text-gold" size={26} />
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

export default Navbar;
